@RestController
@RequestMapping("/api/form")
public class FormPageController {

    private final FormPageService service;

    public FormPageController(FormPageService service) {
        this.service = service;
    }

    @PostMapping("/search")
    public List<FormPageRow> search(@RequestBody FormPageSearchCondition request) {
        // Legacy chain: EgovSampleController.selectScoreList -> EgovSampleServiceImpl.ScoreChk -> SampleDAO.ScoreChk
        // Legacy route: http://127.0.0.1:8080/miplatform/testScoreChk.do
        return service.search(request);
    }

    @GetMapping("/lookups/testcategory")
    public List<FormPageLookupOption> getTestCategoryOptions() {
        // Legacy lookup route: http://127.0.0.1:8080/miplatform/testNameList.do
        return service.getTestCategoryOptions();
    }
}

